const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const app = express();
const port = 3000;

app.use(express.json());

// Elasticsearch client configuration
const esClient = new Client({
  node: 'http://localhost:9200' // Update with your Elasticsearch URL
});

// Middleware to validate index name and query DSL
function validateInput(req, res, next) {
  const { index } = req.params;
  const { query } = req.body;

  if (!index || typeof index !== 'string') {
    return res.status(400).json({ error: 'Invalid index name' });
  }

  if (!query || typeof query !== 'object') {
    return res.status(400).json({ error: 'Invalid query DSL' });
  }

  next();
}

// Route to handle search requests
app.post('/search/:index', validateInput, async (req, res) => {
  const { index } = req.params;
  const { query } = req.body;

  try {
    const response = await esClient.search({ index, body: query });
    res.json(response);
  } catch (error) {
    res.status(500).json({ error: 'Failed to execute search', details: error.message });
  }
});

app.listen(port, () => {
  console.log(`Server is running on http://localhost:${port}`);
});